import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function LoginPage() {
  const [form, setForm] = useState({ email:'', password:'' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.email||!form.password) { toast.error('Please fill in all fields'); return; }
    setLoading(true);
    try {
      const user = await login(form.email, form.password);
      toast.success(`Welcome back, ${user.name.split(' ')[0]}! ✨`);
      navigate(user.role==='admin'?'/admin':'/dashboard');
    } catch(err){ toast.error(err.response?.data?.message||'Login failed'); }
    finally{ setLoading(false); }
  };

  return (
    <>
      <style>{`
        @keyframes starDrift{0%,100%{transform:translateY(0) rotate(0deg);opacity:0.6}50%{transform:translateY(-20px) rotate(180deg);opacity:1}}
        @keyframes bgShimmer{0%,100%{opacity:0.4}50%{opacity:0.7}}
        @keyframes cardGlow{0%,100%{box-shadow:0 24px 64px rgba(0,0,0,0.7),0 0 0 1px #1C2F55}50%{box-shadow:0 24px 64px rgba(0,0,0,0.7),0 0 0 1px #243668,0 0 40px rgba(232,197,71,0.08)}}
        .auth-page{min-height:100vh;display:flex;align-items:center;justify-content:center;position:relative;overflow:hidden;padding:24px;background:#080F20;}
        .auth-stars{position:fixed;inset:0;pointer-events:none;z-index:0;}
        .auth-star{position:absolute;color:#E8C547;animation:starDrift linear infinite;}
        .auth-nebula{position:fixed;inset:0;pointer-events:none;z-index:0;}
        .auth-nebula-blob{position:absolute;border-radius:50%;filter:blur(80px);}
        .auth-card{position:relative;z-index:1;background:rgba(13,27,53,0.92);backdrop-filter:blur(24px);border-radius:22px;padding:44px 48px;width:100%;max-width:440px;border:1px solid #1C2F55;animation:cardGlow 4s ease-in-out infinite;}
        .auth-logo{display:flex;flex-direction:column;align-items:center;gap:12px;margin-bottom:28px;}
        .auth-logo-icon{width:80px;height:80px;border-radius:50%;background:linear-gradient(135deg,#E8C547,#B8960A);display:flex;align-items:center;justify-content:center;font-size:38px;box-shadow:0 8px 32px rgba(232,197,71,0.4),0 0 0 8px rgba(232,197,71,0.08);animation:float 3.5s ease-in-out infinite;}
        .auth-logo-text{font-family:'Playfair Display',serif;font-size:28px;font-weight:700;color:#E8E0D0;text-align:center;}
        .auth-logo-text span{color:#E8C547;font-style:italic;}
        .auth-tagline{font-size:14px;color:#7A8BAD;text-align:center;margin-bottom:32px;}
        .auth-input-group{position:relative;margin-bottom:18px;}
        .auth-input-label{display:block;font-size:11px;font-weight:700;color:#7A8BAD;margin-bottom:7px;text-transform:uppercase;letter-spacing:1px;}
        .auth-input-icon{position:absolute;left:14px;top:38px;font-size:16px;pointer-events:none;}
        .auth-input{width:100%;padding:12px 16px 12px 44px;border-radius:8px;border:1.5px solid #1C2F55;background:#142444;font-size:14px;color:#E8E0D0;transition:all 0.22s;outline:none;font-family:'Plus Jakarta Sans',sans-serif;}
        .auth-input:focus{border-color:#E8C547;box-shadow:0 0 0 3px rgba(232,197,71,0.12);background:#1C2F55;}
        .auth-input::placeholder{color:#3D4F6E;}
        .auth-submit{width:100%;padding:14px;border-radius:999px;background:linear-gradient(135deg,#E8C547,#B8960A);color:#080F20;font-size:15px;font-weight:700;border:none;cursor:pointer;transition:all 0.22s;margin-top:8px;display:flex;align-items:center;justify-content:center;gap:8px;font-family:'Plus Jakarta Sans',sans-serif;}
        .auth-submit:hover:not(:disabled){transform:translateY(-2px);box-shadow:0 8px 28px rgba(232,197,71,0.45);}
        .auth-submit:disabled{opacity:0.5;cursor:not-allowed;transform:none;}
        .auth-divider{display:flex;align-items:center;gap:12px;margin:22px 0;color:#3D4F6E;font-size:12px;}
        .auth-divider::before,.auth-divider::after{content:'';flex:1;height:1px;background:#1C2F55;}
        .auth-demos{display:flex;gap:10px;}
        .auth-demo-btn{flex:1;padding:10px 12px;border-radius:8px;font-size:12px;font-weight:700;background:#0D1B35;border:1.5px solid #1C2F55;color:#7A8BAD;cursor:pointer;transition:all 0.22s;text-align:center;font-family:'Plus Jakarta Sans',sans-serif;}
        .auth-demo-btn:hover{border-color:#E8C547;color:#E8C547;background:rgba(232,197,71,0.05);}
        .auth-footer{text-align:center;margin-top:24px;color:#7A8BAD;font-size:13px;}
        .auth-link{color:#E8C547;font-weight:600;}
        .auth-link:hover{text-decoration:underline;}
        .role-selector{display:flex;gap:10px;margin-bottom:18px;}
        .role-btn{flex:1;padding:10px 12px;border-radius:8px;font-size:13px;font-weight:600;background:#0D1B35;border:1.5px solid #1C2F55;color:#7A8BAD;cursor:pointer;transition:all 0.22s;font-family:'Plus Jakarta Sans',sans-serif;}
        .role-btn.active{background:rgba(232,197,71,0.08);border-color:#E8C547;color:#E8C547;}
        .role-btn:hover:not(.active){border-color:#243668;}
      `}</style>

      <div className="auth-page">
        {/* Stars */}
        <div className="auth-stars">
          {['✦','✧','⋆','✦','★','✧','⋆','✦','✧','✦','⋆','★','✧'].map((s,i)=>(
            <span key={i} className="auth-star" style={{
              left:`${7+i*7}%`,top:`${5+((i*13)%85)}%`,
              fontSize:`${10+((i*7)%14)}px`,opacity:0.4,
              animationDuration:`${3+i*0.8}s`,animationDelay:`${i*0.4}s`
            }}>{s}</span>
          ))}
        </div>
        {/* Nebula blobs */}
        <div className="auth-nebula">
          <div className="auth-nebula-blob" style={{width:500,height:500,background:'radial-gradient(circle,rgba(28,47,85,0.7),transparent)',top:-150,left:-150,animation:'bgShimmer 8s ease-in-out infinite'}}/>
          <div className="auth-nebula-blob" style={{width:400,height:400,background:'radial-gradient(circle,rgba(36,54,104,0.5),transparent)',bottom:-100,right:-100,animation:'bgShimmer 10s ease-in-out infinite reverse'}}/>
          <div className="auth-nebula-blob" style={{width:250,height:250,background:'radial-gradient(circle,rgba(232,197,71,0.04),transparent)',top:'45%',left:'55%',animation:'bgShimmer 6s ease-in-out infinite 2s'}}/>
        </div>

        <div className="auth-card animate-scaleIn">
          <div className="auth-logo">
            <div className="auth-logo-icon">📚</div>
            <div className="auth-logo-text">Library<span>Nest</span></div>
          </div>
          <p className="auth-tagline">Your elegant reading space awaits ✨</p>

          <form onSubmit={handleSubmit}>
            <div className="auth-input-group">
              <label className="auth-input-label">Email Address</label>
              <span className="auth-input-icon">✉️</span>
              <input type="email" className="auth-input" placeholder="you@example.com"
                value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))}/>
            </div>
            <div className="auth-input-group">
              <label className="auth-input-label">Password</label>
              <span className="auth-input-icon">🔑</span>
              <input type="password" className="auth-input" placeholder="Your secret key"
                value={form.password} onChange={e=>setForm(f=>({...f,password:e.target.value}))}/>
            </div>
            <button type="submit" className="auth-submit" disabled={loading}>
              {loading?<><span className="spinner" style={{width:18,height:18,borderTopColor:'#080F20'}}/>Signing in…</>:'✦ Sign In'}
            </button>
          </form>

          <div className="auth-divider">try a demo account</div>
          <div className="auth-demos">
            <button className="auth-demo-btn" onClick={()=>setForm({email:'admin@library.com',password:'admin123'})}>
              👑 Admin
            </button>
            <button className="auth-demo-btn" onClick={()=>setForm({email:'priya@student.com',password:'student123'})}>
              🎓 Student
            </button>
          </div>

          <p className="auth-footer">
            New here? <Link to="/register" className="auth-link">Create an account →</Link>
          </p>
        </div>
      </div>
    </>
  );
}
